import { Avatar as AvatarPrimitive } from '@base-ui/react/avatar';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Avatar.module.css';

type AvatarSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type AvatarProps = AvatarPrimitive.Root.Props & {
  size?: AvatarSize;
};

function Avatar({ className, size, ...props }: AvatarProps) {
  return (
    <AvatarPrimitive.Root
      data-slot="avatar-root"
      data-size={size}
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
}

function AvatarImage({ className, ...props }: AvatarPrimitive.Image.Props) {
  return (
    <AvatarPrimitive.Image
      data-slot="avatar-image"
      className={mergeClassName(className, styles.image)}
      {...props}
    />
  );
}

function AvatarFallback({ className, ...props }: AvatarPrimitive.Fallback.Props) {
  return (
    <AvatarPrimitive.Fallback
      data-slot="avatar-fallback"
      className={mergeClassName(className, styles.fallback)}
      {...props}
    />
  );
}

export { Avatar, AvatarImage, AvatarFallback };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--avatar-size, var(--size-md));
    height: var(--avatar-size, var(--size-md));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    border-radius: var(--avatar-radius, var(--radius-full));
    background-color: var(--avatar-bg, var(--color-muted));
    color: var(--avatar-color, var(--color-foreground));
    font-size: var(--avatar-font-size, var(--text-md));
    font-weight: var(--avatar-font-weight, var(--weight-medium));
    line-height: var(--avatar-line-height, var(--line-height-text-md));
    user-select: none;
    vertical-align: middle;

    &:where([data-size='xs']) {
      --avatar-size: var(--size-xs);
      --avatar-font-size: var(--text-xs);
      --avatar-line-height: var(--line-height-text-xs);
    }

    &:where([data-size='sm']) {
      --avatar-size: var(--size-sm);
      --avatar-font-size: var(--text-sm);
      --avatar-line-height: var(--line-height-text-sm);
    }

    &:where([data-size='lg']) {
      --avatar-size: var(--size-lg);
      --avatar-font-size: var(--text-lg);
      --avatar-line-height: var(--line-height-text-lg);
    }

    &:where([data-size='xl']) {
      --avatar-size: var(--size-xl);
      --avatar-font-size: var(--text-lg);
      --avatar-line-height: var(--line-height-text-lg);
    }
  }

  .image {
    display: block;
    width: 100%;
    height: 100%;
    object-fit: var(--avatar-image-object-fit, cover);
    object-position: var(--avatar-image-object-position, center);
    transition:
      opacity var(--avatar-transition, var(--transition-default)),
      transform var(--avatar-transition, var(--transition-default)),
      translate var(--avatar-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--avatar-image-starting-opacity, 0);
      translate: var(--avatar-image-starting-translate-x, 0)
        var(--avatar-image-starting-translate-y, 0);
      transform: scale(var(--avatar-image-starting-scale, 1));
    }

    &[data-ending-style] {
      opacity: var(--avatar-image-ending-opacity, 0);
      translate: var(--avatar-image-ending-translate-x, 0) var(--avatar-image-ending-translate-y, 0);
      transform: scale(var(--avatar-image-ending-scale, 1));
    }
  }

  .fallback {
    display: inline-flex;
    width: 100%;
    height: 100%;
    align-items: center;
    justify-content: center;
    padding: var(--avatar-fallback-padding, 0);
    background-color: var(--avatar-fallback-bg, var(--avatar-bg, var(--color-muted)));
    color: var(--avatar-fallback-color, inherit);
  }
}
